import{_ as i,o as a,c as t,a4 as s}from"./chunks/framework.CtnSHCpE.js";const g=JSON.parse('{"title":"Git on z/OS","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/GitOnZOS.md","filePath":"Guides/GitOnZOS.md","lastUpdated":1729875856000}'),n={name:"Guides/GitOnZOS.md"};function o(r,e,l,p,d,h){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="git-on-z-os" tabindex="-1">Git on z/OS <a class="header-anchor" href="#git-on-z-os" aria-label="Permalink to &quot;Git on z/OS&quot;">​</a></h1><hr><p><strong>Security Updates:</strong> The Git project regularly releases updates which deal with notified vulnerabilities - their list is <a href="https://github.com/git/git/security/advisories/" target="_blank" rel="noreferrer">here</a>.</p><p>For example, in 2023 the project disclosed <a href="https://github.blog/2023-01-17-git-security-vulnerabilities-announced-2/" target="_blank" rel="noreferrer">two security vulnerabilities</a> affecting v2.39.0 and older releases, and in May 2024, <a href="https://github.com/zopencommunity/gitport/releases/tag/STABLE_gitport_2266" target="_blank" rel="noreferrer">release 2.45.1</a> fixed 5 more which you can read about in the <a href="https://github.blog/2024-05-14-securing-git-addressing-5-new-vulnerabilities/" target="_blank" rel="noreferrer">Github Blog</a>.</p><p>It is important to frequently review the vulnerabilities and keep current with releases available from zopen community.</p><hr><p>Git on z/OS is a version of Git that has been adapted to work on the IBM mainframe operating system, z/OS. It allows developers to take advantage of Git&#39;s powerful version control capabilities while addressing the unique challenges of the mainframe environment. With Git on z/OS, developers can manage their code, collaborate with other developers, and maintain a clear history of the changes that have been made to the codebase.</p><p>You can find the latest information on Git for z/OS by visiting the <a href="https://github.com/zopencommunity/gitport" target="_blank" rel="noreferrer">zopen community gitport repo</a></p><h2 id="encoding-considerations" tabindex="-1">Encoding considerations <a class="header-anchor" href="#encoding-considerations" aria-label="Permalink to &quot;Encoding considerations&quot;">​</a></h2><p>One of the key features of Git on z/OS is its support for various encodings. This is achieved through the use of the <code>.gitattributes</code> file, which can be specified globally or locally in repositories. The <code>.gitattributes</code> file determines the encoding of the working tree files and can be used to convert them to a specific encoding, such as IBM-1047, a commonly used EBCDIC encoding in North America.</p><p>For example, if you want to convert all files in your repository from Git&#39;s internal UTF-8 encoding to IBM-1047, you can add the following line to your <code>.gitattributes</code> file:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>text working-tree-encoding=IBM-1047</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Similarly, if you want the <code>working-tree-encoding</code> to apply to the host platform only, you can use the <code>[platform]-working-tree-encoding</code> attribute, where [platform] should be substituted with the host system that you are on, like so:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>text zos-working-tree-encoding=IBM-1047</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>It is important to note that if no encoding is specified, the default UTF-8 encoding is used and all files are tagged as ISO8859-1.</p><p>To find out all of the supported encodings by git, run <code>iconv -l</code> on z/OS.</p><p>When adding files, you need to make sure that the z/OS file tag matches the <code>working-tree-encoding</code>. Otherwise, you may encounter an error.</p><h2 id="binary-files" tabindex="-1">Binary files <a class="header-anchor" href="#binary-files" aria-label="Permalink to &quot;Binary files&quot;">​</a></h2><p>Another important aspect of Git on z/OS is its handling of binary files. Binary files, such as images, can be specified using the <code>binary</code> attribute in the <code>.gitattributes</code> file. For example, if you want all png files to be treated as binary files, you would use the following line in your .gitattributes file:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.png binary</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>It is important to note that Git on z/OS does not currently support adding untagged files. All files need to be tagged before they can be added to a repository. Additionally, multiple working-tree-encoding attributes can be specified, with later attributes overriding earlier ones in case of an overlap.</p><h2 id="file-tag-verifications" tabindex="-1">File Tag verifications <a class="header-anchor" href="#file-tag-verifications" aria-label="Permalink to &quot;File Tag verifications&quot;">​</a></h2><p>To prevent unexpected syntax errors when building your application, like:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">zopen</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FSUM7332</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> syntax</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> error:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> got</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">expecting</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Newline</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You need to export <code>GIT_UTF8_CCSID</code> before cloning your repo:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GIT_UTF8_CCSID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">819</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Alternatively, you can run the command for global configuration:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.utf8ccsid</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 819</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Or, for local configuration:</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Local configuration will affect only current repository</p></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.utf8ccsid</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 819</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>To ignore file tag verifications between the file system file tag and the encoding specified in the working-tree-encoding, you can use the core.ignorefiletags configuration option. An example is when your files may be tagged as various encodings, but you want them to be treated verbatim regardless of the file tag. By default, Git performs verifications to ensure that the file tag of the Git files matches the tag specified in the working-tree-encoding. The default codepage of a working tree encoding is UTF-8.</p><p>For a global effect, you can use the following command:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.ignorefiletags</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This will disable the file tag verification for all of the repositories on your system.</p><p>For a local repository effect, you can use the following command inside your repository:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.ignoretags</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This will only disable the file tag verification for the specific repository you are currently in.</p><p>It&#39;s important to note that disabling file tag verification may lead to unexpected behavior, so it&#39;s recommended to use this option only if necessary and with caution.</p><h2 id="migration-considerations" tabindex="-1">Migration considerations <a class="header-anchor" href="#migration-considerations" aria-label="Permalink to &quot;Migration considerations&quot;">​</a></h2><p>If you are migrating from Rocket Software&#39;s Git, the good news is that Git on z/OS should be compatible. However, if you encounter any issues, you can open an issue on the <a href="https://github.com/zopencommunity/gitport/issues" target="_blank" rel="noreferrer">Gitport GitHub page</a>.</p>',41)])])}const u=i(n,[["render",o]]);export{g as __pageData,u as default};
